import React, { useEffect, useState } from "react";
import api from "../../api";
import "../../App.css";

import FullCalendar from "@fullcalendar/react";
import dayGridPlugin from "@fullcalendar/daygrid";
import timeGridPlugin from "@fullcalendar/timegrid";
import interactionPlugin from "@fullcalendar/interaction";

export default function Schedule({ user }) {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  const formatEvent = (shift) => {
    const start = new Date(`${shift.date}T${shift.startTime}`);
    const end = new Date(`${shift.date}T${shift.endTime}`);

    return {
      id: shift._id,
      title: `${shift.role}${shift.area ? ` (${shift.area})` : ""}`,
      start,
      end,
      backgroundColor: "#4f46e5",
      borderColor: "#4f46e5"
    };
  };

  useEffect(() => {
    const fetchShifts = async () => {
      try {
        const res = await api.get("/shifts"); // adjust endpoint if needed
        const shifts = res.data.shifts || [];
        setEvents(shifts.map(formatEvent));
      } catch (err) {
        console.error("Failed to load shifts:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchShifts();
  }, []);

  return (
    <div className="su-page">

      {/* TITLE */}
      <div className="su-title mb-4">MY SCHEDULE</div>

      {/* PROFILE SUMMARY BAR */}
      <div
        style={{
          background: "#fff",
          borderRadius: 12,
          padding: "16px 20px",
          marginBottom: 20,
          boxShadow: "0 2px 6px rgba(0,0,0,.06)",
          display: "flex",
          flexWrap: "wrap",
          gap: 20,
          alignItems: "center",
          justifyContent: "space-between"
        }}
      >
        <div>
          <div style={{ fontSize: 12, color: "#888" }}>Name</div>
          <div style={{ fontWeight: 600 }}>
            {user?.name || `${user?.firstName} ${user?.lastName}`}
          </div>
        </div>

        <div>
          <div style={{ fontSize: 12, color: "#888" }}>Role</div>
          <div style={{ fontWeight: 600 }}>
            {user?.position || user?.role}
          </div>
        </div>

        <div>
          <div style={{ fontSize: 12, color: "#888" }}>Availability</div>
          <div style={{ fontWeight: 600 }}>
            {user?.availability || "Not set"}
          </div>
        </div>

        <div>
          <div style={{ fontSize: 12, color: "#888" }}>Email</div>
          <div style={{ fontWeight: 600 }}>
            {user?.email}
          </div>
        </div>
      </div>

      {/* CALENDAR */}
      {loading ? (
        <div style={{ padding: 40 }}>Loading shifts...</div>
      ) : (
        <main className="schedule">
          <FullCalendar
            plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
            initialView="timeGridWeek"
            headerToolbar={{
              left: "prev,next today",
              center: "title",
              right: "dayGridMonth,timeGridWeek,timeGridDay"
            }}
            events={events}
            height="auto"
          />
        </main>
      )}

    </div>
  );
}
